INSERT INTO enrollments (student_id, class_id)
SELECT p.id, c.id
FROM profiles p
CROSS JOIN classes c
WHERE p.role='student' AND p.department='IT' AND p.section='A'
  AND c.department='IT' AND c.section='A'
ON CONFLICT (student_id, class_id) DO NOTHING;